import { useEffect, useState } from "react";
import { roadsService } from "../../services/api";

export default function Traffic() {
  const [roads, setRoads] = useState([]);

  useEffect(() => {
   roadsService.getAll().then(res => setRoads(res.data)).catch(console.error);
  }, []);

  return (
    <main className="page">
      <section className="page-hero">
        <h1>حالة المرور</h1>
        <p>تابع حالة الطرق الرئيسية والكثافة المرورية الحالية.</p>
      </section>

      <section className="cards-grid">
        {roads.map((road) => (
          <div className="info-card" key={road.id}>
            <h3>{road.name}</h3>
            <p>الحالة: {road.status}</p>
            <p>الكثافة: {road.trafficLevel}</p>
          </div>
        ))}
      </section>
    </main>
  );
}
